// Parse XML e extrair dados detalhados do funcionário
const input = $input.first().json;
let xmlData;

try {
  const xmlString = input.xml_ref || '';
  if (!xmlString) {
    throw new Error('XML data not provided');
  }

  // Parse XML simples (assumindo formato <xjx><cmd>...)
  const cmdPattern = /<cmd[^>]*t="([^"]+)"[^>]*>([^<]*)<\/cmd>/g;
  const parsedData = {};
  let match;

  while ((match = cmdPattern.exec(xmlString)) !== null) {
    const key = match[1];
    const value = match[2].trim();

    if (key && key !== 'no-set') {
      parsedData[key] = value;
    }
  }

  xmlData = parsedData;
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'employers_plus_info',
    event: 'xml_parse_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'XML parsing failed', details: error.message }
  };
}

// Função para transformar dados com estrutura de dependentes e benefícios
const transformUserData = (inputData) => {
  const dependentes = {};
  const beneficios = {};
  const globalData = {};

  for (const [key, value] of Object.entries(inputData)) {
    const numberMatch = key.match(/_?(\d+)$/);

    if (!numberMatch) {
      globalData[key] = value;
      continue;
    }

    const number = numberMatch[1];
    const baseKey = key.substring(0, key.lastIndexOf('_'));

    if (baseKey.includes('dependente')) {
      if (!dependentes[number]) dependentes[number] = {};
      dependentes[number][baseKey] = value;
    } else if (baseKey.includes('beneficio')) {
      if (!beneficios[number]) beneficios[number] = {};
      beneficios[number][baseKey] = value;
    }
  }

  return {
    ...globalData,
    dependentes: Object.values(dependentes),
    beneficios: Object.values(beneficios)
  };
};

const transformedData = transformUserData(xmlData);

